import csv, io
from decimal import Decimal, InvalidOperation
def parse_monto(s):
    try:
        return Decimal(s).quantize(Decimal("0.01"))
    except InvalidOperation:
        return None
raw = "id,monto\nC1,10.5\nC2,xx\n"
for row in csv.DictReader(io.StringIO(raw)):
    print(row["id"], parse_monto(row["monto"]))

def quarantine_row(row, reason):
    return {"raw": row, "reason": reason, "status": "quarantine"}
print(quarantine_row(["C1", "x", "y"], "cols 3!=2"))

def validate_schema(obj, required):
    missing = [k for k in required if k not in obj]
    return (len(missing) == 0, missing)
print(validate_schema({"id": "C1", "email": None}, ["id", "email"]))
print(validate_schema({"id": "C1"}, ["id", "email"]))

def is_compatible(old_keys, new_obj):
    return all(k in new_obj for k in old_keys)
print(is_compatible(["id"], {"id": "x", "extra": 1}))

record = {"id": "C1"}
record.setdefault("email", None)
print(record)

def fail_closed(reconcile_ok):
    if not reconcile_ok:
        raise SystemExit(1)
    return 0
print(fail_closed(True))

manifest = {
    "n_in": 10, "n_clean": 8, "n_quarantine": 2,
    "reconcile_ok": 10 == 8 + 2,
}
print(manifest)
if not manifest["reconcile_ok"]:
    raise SystemExit("reconcile failed")
print("publish_ok")
